Fix this topological sort implementation. It fails when there are disconnected nodes.

```python
def topo_sort(graph: dict) -> list:
    visited = set()
    result = []
    def dfs(node):
        visited.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                dfs(neighbor)
        result.append(node)
    for node in graph:
        if node not in visited:
            dfs(node)
    return result
```

The function should return nodes in topological order (dependencies first).

def topo_sort(graph: dict) -> list:
    in_degree = {node: 0 for node in graph}
    for node in graph:
        for neighbor in graph.get(node, []):
            if neighbor not in in_degree:
                in_degree[neighbor] = 0
            in_degree[neighbor] += 1

    queue = [node for node, deg in in_degree.items() if deg == 0]
    result = []

    while queue:
        node = queue.pop(0)
        result.append(node)
        for neighbor in graph.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # Handle disconnected nodes
    all_nodes = set(graph.keys())
    for node in graph:
        all_nodes.update(graph.get(node, []))
    for node in all_nodes - set(result):
        result.append(node)

    return result

