Fix: cycle detection doesn't handle self-loops.

```python
def has_self_loop_or_cycle(graph: dict) -> str:
    """Return 'self-loop', 'cycle', or 'none'."""
    visited = set()
    rec = set()
    def dfs(node):
        visited.add(node)
        rec.add(node)
        for nb in graph.get(node, []):
            if nb not in visited:
                result = dfs(nb)
                if result:
                    return result
            elif nb in rec:
                return 'cycle'
        rec.discard(node)
        return None
    for n in graph:
        if n not in visited:
            r = dfs(n)
            if r:
                return r
    return 'none'
```

