```

Bug: multi-edges between same two nodes give false positive. Parent check only works for single edge. Fix by tracking parent edge index instead.

def has_cycle_undirected(adj: dict) -> bool:
    """Detect cycle in undirected graph using edge index tracking."""
    visited = set()
    edge_stack = []

    def dfs(node, edge_idx):
        visited.add(node)
        for nb in adj.get(node, []):
            edge_key = (min(node, nb), max(node, nb))
            if edge_key not in edge_stack:
                edge_stack.append(edge_key)
                if nb not in visited:
                    if dfs(nb, edge_key):
                        return True
                elif nb != node:
                    if edge_key not in edge_stack:
                        return True
                edge_stack.pop()
            else:
                return True
        return False

    for node in adj:
        if node not in visited:
            edge_stack = []
            if dfs(node, (node, node)):
                return True
    return False

