Fix: topo sort with iterative DFS has stack ordering bug.

```python
def iterative_topo(graph: dict) -> list:
    """Iterative DFS topological sort."""
    visited = set()
    result = []
    for start in graph:
        if start in visited:
            continue
        stack = [start]
        while stack:
            node = stack.pop()
            if node in visited:
                continue
            visited.add(node)
            result.append(node)
            for nb in graph.get(node, []):
                if nb not in visited:
                    stack.append(nb)
    return result
```

Bug: this is just DFS order, not topological order. Need to append after all children are processed.

def iterative_topo(graph: dict) -> list:
    visited = set()
    result = []
    for start in graph:
        if start in visited:
            continue
        stack = [(start, False)]
        while stack:
            node, done = stack.pop()
            if node in visited:
                continue
            if done:
                result.append(node)
                continue
            visited.add(node)
            stack.append((node, True))
            for nb in graph.get(node, []):
                if nb not in visited:
                    stack.append((nb, False))
    return result

