def is_strongly_connected(graph: dict) -> bool:
    """Check if directed graph is strongly connected using Kosaraju's algorithm."""
    if not graph:
        return True

    # Build transposed graph
    transposed = {n: [] for n in graph}
    for n, neighbors in graph.items():
        for nb in neighbors:
            transposed.setdefault(nb, []).append(n)

    # First DFS on original graph
    visited = set()
    stack = [next(iter(graph))]
    while stack:
        n = stack.pop()
        if n in visited:
            continue
        visited.add(n)
        stack.extend(graph.get(n, []))
    if len(visited) != len(graph):
        return False

    # Second DFS on transposed graph from each unvisited node
    visited2 = set()
    for n in graph:
        if n not in visited2:
            visited2.add(n)
            stack = [n]
            while stack:
                curr = stack.pop()
                if curr in visited2:
                    continue
                visited2.add(curr)
                stack.extend(transposed.get(curr, []))

    return visited2 == visited

