import functools
import time
import json

def memoize(ttl=None):
    def decorator(func):
        cache = {}
        def key_builder(*args, **kwargs):
            # Convert unhashable types to hashable representations
            args = tuple(
                json.dumps(a, sort_keys=True, default=str)
                if isinstance(a, (list, dict, set))
                else a
                for a in args
            )
            kwargs = tuple(
                (json.dumps(k, sort_keys=True, default=str), json.dumps(v, sort_keys=True, default=str))
                for k, v in sorted(kwargs.items())
            )
            return (args, kwargs)
        def wrapper(*args, **kwargs):
            key = key_builder(*args, **kwargs)
            if key in cache:
                if ttl is None or time.time() - cache[key][1] < ttl:
                    return cache[key][0]
            result = func(*args, **kwargs)
            cache[key] = (result, time.time())
            return result
        return functools.wraps(func)(wrapper)
    return decorator

@memoize(ttl=60)
def expensive_call(x, y):
    time.sleep(2)
    return x + y

