def diff_dicts(old: dict, new: dict) -> Dict[str, Any]:
    """Compare two dicts. Return {'added', 'removed', 'changed', 'unchanged'}."""
    added = {k: v for k, v in new.items() if k not in old}
    removed = {k: v for k, v in old.items() if k not in new}
    changed = {}
    unchanged = {}
    for k in (set(old) & set(new)):
        if old[k] != new[k]:
