class SlidingWindow:
    def __init__(self, window_size: int):
        self.window_size = window_size
        self.data = []

    def add(self, value: float):
        self.data.append(value)
        if len(self.data) > self.window_size:
            self.data.pop(0)

    def mean(self) -> float:
