def deduplicate_events(events: List[Dict], key_fields: List[str], window_seconds: float) -> List[Dict]:
    key = tuple(sorted(key_fields))
    seen = {}
    result = []
    for e in sorted(events, key=lambda x: x['timestamp']):
        k = tuple(e[f] for f in key)
        if k not in seen:
            seen[k] = time.time()
            result.append(e)
        else:
            if time.time() - seen[k] <= window_seconds:
                result.append(e)
            else:
                seen[k] = time.time()
    return sorted(result, key=lambda x: x['timestamp'])

