class CircuitBreaker:
    def __init__(self, failure_threshold: int, reset_timeout: float):
        self.failure_threshold = failure_threshold
        self.reset_timeout = reset_timeout
        self.last_failure_time = 0.0
        self.failures = 0
        self.is_open = False

    def call(self, timestamp: float, success: bool):
        if self.is_open:
            self.failures = 0
            self.is_open = False
            return
        if success:
            self.failures = 0
        else:
            self.failures += 1
            if self.failures >= self.failure_threshold:
                self.is_open = True
                self.last_failure_time = timestamp
            else:
                self.last_failure_time = timestamp

    def is_open(self, timestamp: float) -> bool:
        if self.is_open:
            if timestamp - self.last_failure_time > self.reset_timeout:
                self.is_open = False
                self.failures = 0
            return self.is_open
        return False

