class Trie:
    def __init__(self):
        self.root = {}
        self.words = set()

    def insert(self, word: str) -> None:
        node = self.root
        for c in word:
            if c not in node:
                node[c] = {}
            node = node[c]
        node['$'] = True
        self.words.add(word)

    def search(self, word: str) -> bool:
        node = self.root
        for c in word:
            if c not in node:
                return False
            node = node[c]
        return node.get('$', False)

    def starts_with(self, prefix: str) -> list[str]:
        node = self.root
        for c in prefix:
            if c not in node:
                return []
            node = node[c]
        results = []
        def collect(node, prefix):
            if '$' in node:
                results.append(prefix)
            for k, v in node.items():
                if k != '$':
                    collect(v, prefix + k)
        collect(node, prefix)
        return sorted(results)

