def compute_percentiles(values: list[float], percentiles: list[float]) -> dict:
    if not values:
        return {p: 0.0 for p in percentiles}
    s = sorted(values)
    n = len(s)
    result = {}
    for p in percentiles:
        idx = (p / 100) * (n - 1)
        lower = int(idx)
        upper = min(lower + 1, n - 1)
        frac = idx - lower
        result[p] = s[lower] * (1 - frac) + s[upper] * frac
    return result
