class ConnectionPool:
    def __init__(self, max_size: int):
        self.max_size = max_size
        self.next_id = 0
        self.active_conns = set()
    def acquire(self) -> int:
        if len(self.active_conns) >= self.max_size:
            return -1
        conn_id = self.next_id
        self.next_id += 1
        self.active_conns.add(conn_id)
        return conn_id
    def release(self, conn_id: int) -> bool:
        if conn_id in self.active_conns:
            self.active_conns.discard(conn_id)
            return True
        return False
    def active(self) -> int:
        return len(self.active_conns)
