from collections import deque

def topological_sort(graph: dict) -> list:
    in_degree = {n: 0 for n in graph}
    for node, deps in graph.items():
        for dep in deps:
            if dep not in in_degree:
                in_degree[dep] = 0
            in_degree[node] = max(in_degree.get(node, 0), in_degree.get(node, 0))
    in_degree = {n: len(deps) for n, deps in graph.items()}
    queue = deque([n for n, d in in_degree.items() if d == 0])
    result = []
    while queue:
        n = queue.popleft()
        result.append(n)
        for nb in graph:
            if n in graph[nb]:
                in_degree[nb] -= 1
                if in_degree[nb] == 0:
                    queue.append(nb)
    if len(result) != len(in_degree):
        raise ValueError("Cycle detected")
    return result

def int_to_roman(num: int) -> str:
    """Convert an integer (1–3999) to a Roman numeral string."""
    if not (1 <= num <= 3999):
        raise ValueError("num must be in range 1–3999")
    table = [
        (1000, 'M'), (900, 'CM'), (500, 'D'), (400, 'CD'),
        (100, 'C'), (90, 'XC'), (50, 'L'), (40, 'XL'),
        (10, 'X'), (9, 'IX'), (5, 'V'), (4, 'IV'), (1, 'I')
    ]
    result = []
    for value, symbol in table:
        while num >= value:
            result.append(symbol)
            num -= value
    return ''.join(result)

