            raise ValueError(f"Unknown Japanese format: {phone}")
        else:
            raise ValueError(f"Unknown format: {phone}")
    else:
        # Already has +
        if len(digits) == 12 and digits[1] == '1':
            return '+' + digits[2:]
        return '+' + digits

