def diff_dicts(old: dict, new: dict) -> dict:
    """Compare two dicts. Return {added, removed, changed, unchanged}."""
    old = {k: v for k, v in old.items()}
    new = {k: v for k, v in new.items()}

    added = {k: new[k] for k in new if k not in old}
    removed = {k: old[k] for k in old if k not in new}
    changed = {k: new[k] for k in old & new if old[k] != new[k]}
    unchanged = {k: old[k] for k in old & new if old[k] == new[k]}

    return {
        'added': added,
        'removed': removed,
        'changed': changed,
        'unchanged': unchanged
    }

