def map_reduce(items: list, mapper: Callable, reducer: Callable) -> dict:
    keys: Dict[str, List[Any]] = {}
    for item in items:
        for k, v in mapper(item):
            if k not in keys: keys[k] = []
            keys[k].append(v)
    return {k: reducer(k, vals) for k, vals in keys.items()}

