from typing import Any, Dict, List, Optional

def validate_config(config: dict, schema: dict) -> dict:
    errors: List[str] = []
    validated = dict(config)

    for key, spec in schema.items():
        if key not in config:
            if spec.get('required', False):
                errors.append(f"Missing required key: {key}")
                continue
            if 'default' in spec:
                validated[key] = spec['default']
        else:
            value = config[key]
            expected_type = spec.get('type', type(value))
            if expected_type == 'list' and not isinstance(value, list):
                errors.append(f"Key '{key}': expected list, got {type(value).__name__}")
            elif expected_type == 'dict' and not isinstance(value, dict):
                errors.append(f"Key '{key}': expected dict, got {type(value).__name__}")
            elif not isinstance(value, expected_type):
                errors.append(f"Key '{key}': expected {expected_type}, got {type(value).__name__}")

    return {
        'valid': len(errors) == 0,
        'errors': errors,
        'config': validated
    }

import re

def parse_content_type(header: str) -> dict:
    m = re.match(r'(\w+)/(\w+)(?:;(.*))', header)
    if not m:
        raise ValueError(f"Invalid header: {header}")
    params = {}
    if m.group(3):
        for p in m.group(3).split(';'):
            p = p.strip().lower()
            if '=' in p:
                k, v = p.split('=', 1)
                params[k.strip()] = v.strip().strip('"').strip("'")
    return {'type': m.group(1), 'subtype': m.group(2), 'params': params}

def exponential_moving_average(values, alpha=0.3):
    if not values:
        return []
    ema = [values[0]]
    for v in values[1:]:
        ema.append(alpha * v + (1 - alpha) * ema[-1])
    return ema

