from urllib.parse import unquote_plus
from urllib.parse import parse_qsl

def parse_query_string(qs: str) -> dict:
    """Parse URL query string into dict, URL-decoding key and value."""
    if not qs:
        return {}
    # parse_qsl returns list of (key, value) tuples
    pairs = parse_qsl(qs, keep_blank_values=True)
    result = {}
    for key, value in pairs:
        key = unquote_plus(key)
        value = unquote_plus(value)
        if key in result:
            result[key].append(value)
        else:
            result[key] = [value]
    return result

class ConnectionPool:
    def __init__(self, max_size: int):
        self.max_size = max_size
        self.pool: set = set()
        self.in_use: set = set()
        self.counter = 0
        self.lock = None

    def acquire(self) -> int:
        if not self.pool:
            self.counter += 1
            return -1
        conn_id = self.pool.pop()
        self.in_use.add(conn_id)
        return conn_id

    def release(self, conn_id: int) -> bool:
        if conn_id not in self.in_use:
            return False
        self.in_use.discard(conn_id)
        self.pool.add(conn_id)
        return True

    def active(self) -> int:
        return len(self.in_use)

