class StateMachine:
    def __init__(self, states, transitions, initial):
        self.states = set(states)
        self.transitions = {t['from']: {e: t['to'] for e, t in t['transitions']} for t in transitions}
        self.current = initial
        self.history = []
        self._last_event = None

    def trigger(self, event):
        if self.current in self.transitions and event in self.transitions[self.current]:
            self.current = self.transitions[self.current][event]
            self.history.append(event)
            return True
        return False

    def current_state(self):
        return self.current

    def history(self):
        return list(self.history)

    def can_trigger(self, event):
        return self.current in self.transitions and event in self.transitions[self.current]

